import{_ as o,Z as e,P as r,g as n,k as s,m as t}from"./chunks/framework.Dp5g00Bf.js";const u=JSON.parse('{"title":"Excel行数据转Word卡片数据","description":"","frontmatter":{},"headers":[],"relativePath":"views/2-软件📲/办公软件操作/Excel行数据转Word卡片数据/index.md","filePath":"views/2-软件📲/办公软件操作/Excel行数据转Word卡片数据/index.md","lastUpdated":1778336291000}'),d={name:"views/2-软件📲/办公软件操作/Excel行数据转Word卡片数据/index.md"};function m(c,i,g,p,h,v){const a=e("NolebaseGitContributors"),l=e("NolebaseGitChangelog");return r(),n("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1778336291000"},[i[0]||(i[0]=s('<h1 id="excel行数据转word卡片数据" tabindex="-1">Excel行数据转Word卡片数据 <a class="header-anchor" href="#excel行数据转word卡片数据" aria-label="Permalink to &quot;Excel行数据转Word卡片数据&quot;">​</a></h1><p>我们在项目中，默认情况下是用我们的Excel用例模版输出测试用例。但是有的项目中，会要求在Word版本的测试计划或者测试报告中，写明测试用例。而我们的测试用例，有的项目有上千条，这个时候如果从Excel往Word中复制粘贴，手工工作量很大。这里我们采用微软Office Word的“邮件合并”功能，快速将Excel的测试用例转换为Word表格。</p><h2 id="具体步骤" tabindex="-1">具体步骤 <a class="header-anchor" href="#具体步骤" aria-label="Permalink to &quot;具体步骤&quot;">​</a></h2><ol><li>按Word文档要求，创建一个空的表格，参考下图（这里建议在表格后加两个回车换行，否则最后批量生成的表格会变成连体表格）</li></ol><p><img src="https://cdn.jsdelivr.net/gh/Ruin-L/image@main/img/20260224104338427.avif" alt="img"></p><ol start="2"><li>按word文档要求，修改excel用例。注意，excel用例字段，必须包含步骤1表格中的字段；我这里是把字段修改成完全一致。</li></ol><p><img src="https://cdn.jsdelivr.net/gh/Ruin-L/image@main/img/20260224104541405.avif" alt=""></p><ol start="3"><li>在Word中，点击“邮件&gt;开始邮件合并&gt;目录”；</li></ol><p><img src="https://cdn.jsdelivr.net/gh/Ruin-L/image@main/img/20260224105304330.avif" alt=""></p><ol start="4"><li>在邮件页面，点击“选择收件人&gt;使用现有列表”，选择测试用例excel文件，点击“打开”按钮；</li></ol><p><img src="https://cdn.jsdelivr.net/gh/Ruin-L/image@main/img/20260224105329781.avif" alt=""></p><ol start="5"><li>选择测试用例所在的sheet页，点击“确定”按钮；</li></ol><p><img src="https://cdn.jsdelivr.net/gh/Ruin-L/image@main/img/20260224105400028.avif" alt=""></p><ol start="6"><li>在word文档中，鼠标点击第一个字段的内容处，激活光标；点击对应的项，会将字段插入到对应的位置；</li></ol><p><img src="https://cdn.jsdelivr.net/gh/Ruin-L/image@main/img/20260224105635353.avif" alt=""></p><ol start="7"><li>重复步骤6，直到所有字段都插入完成；</li></ol><p><img src="https://cdn.jsdelivr.net/gh/Ruin-L/image@main/img/20260224110022526.avif" alt=""></p><ol start="8"><li>此时，点击“预览结果”，可以检查一下配置的字段是否正确；如果有不正确的，可以重新执行插入合并域操作；</li></ol><p><img src="https://cdn.jsdelivr.net/gh/Ruin-L/image@main/img/20260224110116154.avif" alt=""></p><ol start="9"><li>字段配置正确后，点击“完成并合并&gt;编辑单个文档”，在弹出的合并记录选择窗口，可以配置要合并数据记录范围，我这里是合并全部数据，直接点击“确定”按钮，开始批量生成word表格；</li></ol><p><img src="https://cdn.jsdelivr.net/gh/Ruin-L/image@main/img/20260224110206750.avif" alt=""></p><p><img src="https://cdn.jsdelivr.net/gh/Ruin-L/image@main/img/20260224110247501.avif" alt=""></p><p><img src="https://cdn.jsdelivr.net/gh/Ruin-L/image@main/img/20260224110453513.avif" alt=""></p><blockquote><p>推荐使用微软的word和excel，一方面速度更快，另外一方面，可以避免Word无法识别该外部表的格式（比如在线表格的导出格式、链接方式与Word的兼容问题）。如下图一开始使用腾讯在线文档导出的excel并不能直接在word种使用。</p></blockquote><p><img src="https://cdn.jsdelivr.net/gh/Ruin-L/image@main/img/20260224110729659.avif" alt=""></p>',25)),t(a),t(l)])}const x=o(d,[["render",m]]);export{u as __pageData,x as default};
